import React from 'react';
import Header from '../components/Header';
import Footer from '../components/Footer';

const NewProductsPage = () => {
  const newProducts = [
    { id: 1, name: "Camiseta Oversized", price: 129.90, image: "https://via.placeholder.com/200" },
    { id: 2, name: "Calça Cargo", price: 259.90, image: "https://via.placeholder.com/200" },
    { id: 3, name: "Moletom Graphic", price: 199.90, image: "https://via.placeholder.com/200" },
    { id: 4, name: "Tênis Urban", price: 399.90, image: "https://via.placeholder.com/200" },
  ];

  const featuredNews = [
    {
      id: 1,
      title: "Nova Coleção Verão",
      description: "Descubra as últimas tendências em street wear para o verão.",
      image: "https://via.placeholder.com/400x200"
    },
    {
      id: 2,
      title: "Colaboração Exclusiva",
      description: "Uma parceria única com artistas urbanos locais.",
      image: "https://via.placeholder.com/400x200"
    },
    {
      id: 3,
      title: "Promoção Limitada",
      description: "Aproveite descontos especiais em peças selecionadas.",
      image: "https://via.placeholder.com/400x200"
    }
  ];

  return (
    <div className="min-h-screen bg-amber-50">
      <Header />

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold text-black mb-8 text-center">Novos produtos</h1>

        {/* Products Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 mb-12">
          {newProducts.map((product) => (
            <div key={product.id} className="bg-white rounded-lg shadow-md overflow-hidden border-2 border-amber-400 hover:border-black transition-colors duration-300">
              <img
                src={product.image}
                alt={product.name}
                className="w-full h-48 object-cover"
              />
              <div className="p-4">
                <h3 className="font-medium text-black">{product.name}</h3>
                <p className="text-lg font-bold text-amber-600 mt-1">
                  R$ {product.price.toFixed(2)}
                </p>
              </div>
            </div>
          ))}
        </div>

        {/* Featured News Section */}
        <div className="space-y-6">
          {featuredNews.map((news) => (
            <div key={news.id} className="bg-white rounded-lg shadow-md overflow-hidden border-l-4 border-amber-400">
              <div className="p-4">
                <div className="flex flex-col md:flex-row gap-6">
                  <img
                    src={news.image}
                    alt={news.title}
                    className="w-full md:w-1/3 h-48 object-cover rounded-lg"
                  />
                  <div className="flex-1">
                    <h2 className="text-xl font-bold text-black mb-2">{news.title}</h2>
                    <p className="text-gray-600">{news.description}</p>
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>

      <Footer />
    </div>
  );
};

export default NewProductsPage;
